"use strict";(globalThis.webpackChunkjournal=globalThis.webpackChunkjournal||[]).push([[7771],{2141:a=>{a.exports=JSON.parse('{"permalink":"/journal/blog/2025/01/20/","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2025-01-20.mdx","source":"@site/blog/2025-01-20.mdx","title":"De los Andes al Mediterr\xe1neo: Mi traves\xeda hacia Malta.","description":"8.000 Kil\xf3metros por un Sue\xf1o: Bogot\xe1, Madrid y La Valeta.","date":"2025-01-20T00:00:00.000Z","tags":[{"inline":true,"label":"ExperienciaMalta","permalink":"/journal/blog/tags/experiencia-malta"},{"inline":true,"label":"Colombia","permalink":"/journal/blog/tags/colombia"},{"inline":true,"label":"Espa\xf1a","permalink":"/journal/blog/tags/espana"},{"inline":true,"label":"Malta","permalink":"/journal/blog/tags/malta"},{"inline":true,"label":"Ingl\xe9s","permalink":"/journal/blog/tags/ingles"},{"inline":true,"label":"AMLanguage","permalink":"/journal/blog/tags/am-language"}],"readingTime":15.74,"hasTruncateMarker":false,"authors":[{"name":"Luis Miguel B\xe1ez","title":"Systems and Computer Engineer at UNAL and ACM-ICPC contestant","url":"https://github.com/LuchoBazz","socials":{"github":"https://github.com/LuchoBazz","linkedin":"https://www.linkedin.com/in/luismiguelbaez/","x":"https://x.com/luchobazz"},"imageURL":"https://avatars.githubusercontent.com/u/22530481","key":"luchobazz","page":null}],"frontMatter":{"title":"De los Andes al Mediterr\xe1neo: Mi traves\xeda hacia Malta.","description":"8.000 Kil\xf3metros por un Sue\xf1o: Bogot\xe1, Madrid y La Valeta.","authors":"luchobazz","tags":["ExperienciaMalta","Colombia","Espa\xf1a","Malta","Ingl\xe9s","AMLanguage"]},"unlisted":false,"prevItem":{"title":"De Malta a la \'Dolce Vita\': Mi Aventura Italiana de 2025","permalink":"/journal/blog/2025/06/22/"},"nextItem":{"title":"Traves\xeda hacia el Training Camp 2023","permalink":"/journal/blog/2023/07/28/"}}')},3688:(a,e,o)=>{o.r(e),o.d(e,{assets:()=>t,contentTitle:()=>s,default:()=>u,frontMatter:()=>l,metadata:()=>n,toc:()=>d});var n=o(2141),r=o(4848),i=o(8453);const l={title:"De los Andes al Mediterr\xe1neo: Mi traves\xeda hacia Malta.",description:"8.000 Kil\xf3metros por un Sue\xf1o: Bogot\xe1, Madrid y La Valeta.",authors:"luchobazz",tags:["ExperienciaMalta","Colombia","Espa\xf1a","Malta","Ingl\xe9s","AMLanguage"]},s=void 0,t={authorsImageUrls:[void 0]},d=[{value:"Viaje de Bogot\xe1 a Madrid",id:"viaje-de-bogot\xe1-a-madrid",level:3},{value:"Primeras horas en Madrid",id:"primeras-horas-en-madrid",level:3},{value:"Conociendo Madrid",id:"conociendo-madrid",level:3},{value:"Tour de Estadios",id:"tour-de-estadios",level:3},{value:"Rumbo al Aeropuerto",id:"rumbo-al-aeropuerto",level:3},{value:"Conexi\xf3n y Despegue",id:"conexi\xf3n-y-despegue",level:3},{value:"Vuelo de Madrid a Malta",id:"vuelo-de-madrid-a-malta",level:3},{value:"Llegada a Malta",id:"llegada-a-malta",level:3},{value:"Instalaci\xf3n y reconocimiento de la zona",id:"instalaci\xf3n-y-reconocimiento-de-la-zona",level:3},{value:"Primer d\xeda de clases",id:"primer-d\xeda-de-clases",level:3},{value:"El inicio de las clases",id:"el-inicio-de-las-clases",level:3}];function c(a){const e={code:"code",h3:"h3",hr:"hr",p:"p",strong:"strong",...(0,i.R)(),...a.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(e.p,{children:"La planificaci\xf3n de esta aventura comenz\xf3 alrededor de abril de 2024, respaldada por un a\xf1o y medio previo de austeridad y ahorro. Mi meta principal para ese a\xf1o era romper la barrera del idioma: quer\xeda superar mi frustrante nivel A1-A2 y alcanzar un s\xf3lido B2 en ingl\xe9s. Los m\xe9todos de estudio tradicionales me aburr\xedan y no habian sido nada efectivo en mi progreso, por lo que decid\xed sumergirme en un entorno donde el ingl\xe9s fuera lengua oficial y nativa. Sab\xeda que ser\xeda una inversi\xf3n mayor, pero confiaba en que ser\xeda la v\xeda m\xe1s efectiva para aprender."}),"\n",(0,r.jsx)(e.p,{children:"Explor\xe9 diversas opciones con la mente abierta, priorizando la accesibilidad econ\xf3mica frente a los costosos destinos tradicionales como Estados Unidos, Canad\xe1, Inglaterra o Australia. En la investigaci\xf3n que hice, me dio tres candidatos prometedores y populares entre las agencias de idiomas: Sud\xe1frica, Jamaica y Malta. Inicialmente, mi hermano Nacho, quien tomaba clases con una profesora jamaiquina, me anim\xf3 a considerar el Caribe y por momentos me visualic\xe9 all\xed. Sin embargo, al profundizar en internet, Malta cobr\xf3 protagonismo. Se destacaba como un destino europeo asequible y muy popular entre la comunidad latina, con abundantes rese\xf1as y testimonios que validaban la experiencia."}),"\n",(0,r.jsxs)(e.p,{children:["Para sortear el engorroso tr\xe1mite de visado, descubr\xed ",(0,r.jsx)(e.code,{children:"Vivirse"}),", una agencia con excelente reputaci\xf3n y gran cantidad de contenido sobre la isla. Su modelo de negocio me convenci\xf3 de inmediato: yo pagaba el curso directamente a la escuela elegida y esta se encargaba de cubrir los honorarios de la agencia por la gesti\xf3n de los tr\xe1mites, evit\xe1ndome costos extra por el servicio. Tras contactarlos, me explicaron detalladamente el proceso y los requisitos, tales como demostrar fondos suficientes para siete meses de estancia y adquirir los tiquetes de ida."]}),"\n",(0,r.jsxs)(e.p,{children:["Solicit\xe9 un tiempo de espera de un mes para analizar presupuestos y evaluar las escuelas antes de realizar el pago. Justo antes de finalizar el plazo, apareci\xf3 una gran oportunidad: ",(0,r.jsx)(e.code,{children:"AM Language"}),", una de las escuelas m\xe1s costosas, lanz\xf3 una promoci\xf3n de invierno con un 50% de descuento sobre sus tarifas de verano. Sin dudarlo, aprovech\xe9 esta oferta para concretar mi viaje."]}),"\n",(0,r.jsxs)(e.p,{children:["A finales de agosto, aprovech\xe9 la oferta y realic\xe9 el pago del curso. De inmediato, ",(0,r.jsx)(e.code,{children:"Vivirse"})," me envi\xf3 una gu\xeda detallada con el cronograma y la lista de requisitos para la visa, incluyendo la reserva de la primera semana de alojamiento en Airbnb y los tiquetes a\xe9reos. El acompa\xf1amiento de la agencia fue constante y fundamental durante esta etapa."]}),"\n",(0,r.jsx)(e.p,{children:"El proceso de reunir y traducir los documentos al ingl\xe9s fue un verdadero desaf\xedo que me tom\xf3 varios fines de semana. Pas\xe9 por tres rondas de revisi\xf3n con la agencia, corrigiendo observaciones y ajustando detalles una y otra vez, hasta que finalmente logr\xe9 completar el check list con todos los requisitos necesarios."}),"\n",(0,r.jsxs)(e.p,{children:["Para cumplir con la exigencia de los tiquetes, me recomendaron una estrategia log\xedstica: compr\xe9 los trayectos por separado para hacer una escala intencional de tres d\xedas y conocer Madrid. El primer vuelo, el ",(0,r.jsx)(e.code,{children:"LA1604"})," de Latam, saldr\xeda de Bogot\xe1 rumbo a Madrid el 22 de enero de 2025 a las 2:10 p.m.; el segundo, el ",(0,r.jsx)(e.code,{children:"FR5382"})," de Ryanair, partir\xeda de Madrid hacia Malta el 25 de enero a las 10:00 a.m. Esta combinaci\xf3n, incluso sumando los d\xedas de alojamiento en Espa\xf1a, result\xf3 m\xe1s econ\xf3mica que las opciones de vuelo directo ofrecidas por las agencias."]}),"\n",(0,r.jsxs)(e.p,{children:["Dado que Malta no cuenta con embajada en Colombia, ",(0,r.jsx)(e.code,{children:"Vivirse"})," me ayud\xf3 a agendar la cita con la empresa encargada de recolectar la documentaci\xf3n. Me present\xe9 en su oficina en Bogot\xe1 a principios de noviembre de 2024; all\xed revisaron mi carpeta, aceptaron los documentos y retuvieron mi pasaporte para el tr\xe1mite. Aproximadamente un mes despu\xe9s, entre la primera y segunda semana de diciembre, recib\xed un paquete en la casa de mis padres, con una gran noticia: lleg\xf3 mi pasaporte con la visa aprobada."]}),"\n",(0,r.jsx)(e.h3,{id:"viaje-de-bogot\xe1-a-madrid",children:"Viaje de Bogot\xe1 a Madrid"}),"\n",(0,r.jsx)(e.p,{children:"Tras pasar los \xfaltimos d\xedas en familia en Circasia, Quind\xedo, lleg\xf3 el momento de partir. Mi madre y mi padrastro decidieron acompa\xf1arme hasta Bogot\xe1 para despedirme; tomamos un bus dos d\xedas antes del vuelo y llegamos a la capital de madrugada. Dado que mis vacaciones laborales comenzaban oficialmente el d\xeda del viaje, tuve que trabajar ese \xfaltimo d\xeda desde la casa de mi hermano Andr\xe9s Felipe. Por la noche, nos trasladamos a un Airbnb para descansar antes del viaje."}),"\n",(0,r.jsx)(e.p,{children:"A la ma\xf1ana siguiente, como el vuelo estaba programado para las 2:10 p.m., aprovechamos para reunirnos con mi hermano Juan. Compartimos un caf\xe9 y disfrutamos de nuestros \xfaltimos momentos juntos antes de mi partida. Alrededor de las 9:00 a.m., tomamos un Transmilenio desde la estaci\xf3n de Ciudad Universitaria rumbo al Aeropuerto El Dorado, llegando unos 30 minutos despu\xe9s."}),"\n",(0,r.jsx)(e.p,{children:"Tuvimos que esperar una hora antes de poder entregar el equipaje de bodega. Durante ese tiempo, not\xe9 que mi vuelo hab\xeda cambiado de Latam a Iberia; aunque no recib\xed una explicaci\xf3n oficial, supuse que se debi\xf3 a una unificaci\xf3n de vuelos por disponibilidad. Realic\xe9 el check-in y, tras una espera final, lleg\xf3 la emotiva hora de la despedida a las 12:00 p.m. Entre sentimientos encontrados y tristeza, nos tomamos las \xfaltimas fotos antes de cruzar migraci\xf3n y dirigirme a la sala de espera."}),"\n",(0,r.jsx)(e.p,{children:"El abordaje comenz\xf3 cerca de la 1:00 p.m. Ya en el avi\xf3n, un avi\xf3n grande de tres filas, nos entregaron almohada, cobija y auriculares. El acento espa\xf1ol de los auxiliares de vuelo me confirm\xf3 que mi aventura europea hab\xeda comenzado. El despegue se realiz\xf3 sin contratiempos y, unos 40 minutos despu\xe9s, viv\xed un momento de profunda nostalgia al ver en la pantalla del GPS que sobrevol\xe1bamos el pueblo de mis abuelos y mi lugar de nacimiento."}),"\n",(0,r.jsx)(e.p,{children:"Durante el vuelo nos sirvieron arroz con pollo, ensalada y postre. Al caer la tarde, las luces de la cabina se atenuaron y pude ver el sol ocult\xe1ndose en el horizonte sobre el oc\xe9ano. A pesar de intentar descansar, la ansiedad y la incomodidad de la silla no me permitieron dormir. Pas\xe9 el tiempo intentando ver pel\xedculas sin lograr concentrarme; sent\xeda que el viaje se hac\xeda eterno. Finalmente, tras casi 10 horas, 8.030 kil\xf3metros recorridos y una altura m\xe1xima de 12.518 metros, aterrizamos en el Aeropuerto Adolfo Su\xe1rez Madrid-Barajas alrededor de las 6:10 a.m. Tuve que pasar por migraci\xf3n: hab\xeda fila para europeos y no europeos, as\xed que fui hacia la de no europeos. Al llegar mi turno me preguntaron el motivo del viaje; les expliqu\xe9 que estar\xeda 3 d\xedas en Madrid y que luego continuar\xeda a Malta para estudiar ingl\xe9s. Como llevaba visa de estudiante, no me pusieron ning\xfan problema y me sellaron el pasaporte sin inconvenientes."}),"\n",(0,r.jsx)(e.h3,{id:"primeras-horas-en-madrid",children:"Primeras horas en Madrid"}),"\n",(0,r.jsx)(e.p,{children:"Una vez con mi maleta en mano, busqu\xe9 una zona con conexi\xf3n a internet para comprar una eSIM y asegurar la conexi\xf3n con Google Maps. Decid\xed esperar unas dos horas en el aeropuerto, ya que al ser invierno, el sol sal\xeda tarde y a\xfan estaba oscuro. Cerca de las 9:00 a.m., me dirig\xed a la estaci\xf3n de metro, compr\xe9 mi tarjeta y puse rumbo a Los Rosales, en el sur de Madrid, donde se ubicaba mi alojamiento."}),"\n",(0,r.jsx)(e.p,{children:"Como el check-in estaba programado para las 3:00 p.m., contact\xe9 a la anfitriona, quien amablemente me permiti\xf3 llegar antes para dejar el equipaje. Me sorprendi\xf3 mucho de ese primer trayecto en metro; me sent\xed seguro y me sorprendi\xf3 la limpieza, el silencio y la multiculturalidad de la ciudad."}),"\n",(0,r.jsx)(e.h3,{id:"conociendo-madrid",children:"Conociendo Madrid"}),"\n",(0,r.jsx)(e.p,{children:"Tras un viaje de 45 minutos, llegu\xe9 a la estaci\xf3n de metro Villaverde Bajo-Cruce. El d\xeda me recibi\xf3 gris y con una ligera llovizna, por lo que esper\xe9 unos 15 minutos hasta que escamp\xf3 para caminar hacia el Airbnb guiado por el GPS. Aunque se trataba de un barrio popular, la zona me pareci\xf3 muy linda; all\xed empec\xe9 a percibir el aut\xe9ntico ambiente madrile\xf1o y disfrut\xe9 mucho del recorrido."}),"\n",(0,r.jsx)(e.p,{children:"Unos diez minutos despu\xe9s, llegu\xe9 a la ubicaci\xf3n indicada, pero no lograba encontrar el acceso. Contact\xe9 a la anfitriona, quien me vio desde la ventana y me indic\xf3 que la entrada se encontraba en la parte posterior del conjunto residencial. Al llegar v\xed un gran port\xf3n, lo empuje pero la cerradura se resisti\xf3 un poco; tuve que forcejear un par de veces hasta lograr abrirla. Ya en el apartamento, la se\xf1ora fue muy amable: me explic\xf3 el funcionamiento de todo y me aconsej\xf3 tener precauci\xf3n con los carteristas/cosquilleo en el sistema de transporte. Sal\xed de inmediato a buscar desayuno y, tras consultar el GPS, encontr\xe9 un supermercado cercano donde compr\xe9 algo para comer."}),"\n",(0,r.jsx)(e.p,{children:"Posteriormente, tom\xe9 el metro rumbo al centro hist\xf3rico y fu\xed hacia la estaci\xf3n Puerta del Sol. Hac\xeda bastante fr\xedo, con una temperatura entre 10 y 12 grados. Camin\xe9 por la zona tur\xedstica, sorprendido por la belleza, limpieza y elegancia de la ciudad. Me dej\xe9 llevar sin un rumbo fijo, tomando muchas fotos y disfrutando cada instante."}),"\n",(0,r.jsx)(e.p,{children:"Durante el recorrido visit\xe9 la Plaza del Sol, la Plaza Mayor y sus alrededores, la Plaza de Oriente, el Palacio Real, el Congreso de los Diputados, la Real Academia Espa\xf1ola, Callao y el Parque de El Retiro con su Palacio de Cristal. Hice una parada estrat\xe9gica en el Mercado de San Miguel, donde hab\xeda una feria de Jam\xf3n Ib\xe9rico. Aprovech\xe9 para almorzar un plato de tres tipos de jamones acompa\xf1ados de queso y hierbas; fue una porci\xf3n ligera pero deliciosa. Continu\xe9 explorando la ciudad hasta las 9:30 p.m."}),"\n",(0,r.jsx)(e.p,{children:"Para el d\xeda siguiente, organic\xe9 un tour por los dos estadios m\xe1s importantes de la ciudad: el Santiago Bernab\xe9u del Real Madrid y el Riyadh Air Metropolitano del Atl\xe9tico de Madrid. Sent\xeda una mezcla de nostalgia y emoci\xf3n por visitar estos templos deportivos, escenarios del f\xfatbol espa\xf1ol que marcaron mi infancia y adolescencia."}),"\n",(0,r.jsx)(e.h3,{id:"tour-de-estadios",children:"Tour de Estadios"}),"\n",(0,r.jsx)(e.p,{children:"A las 10:30 a.m. sal\xed de la estaci\xf3n Villaverde Bajo-Cruce rumbo a la estaci\xf3n Santiago Bernab\xe9u, llegando cerca de las 11:30 a.m. La primera impresi\xf3n fue impactante: el estadio luc\xeda muy diferente a lo que recordaba de la televisi\xf3n debido a las recientes remodelaciones que le daban un aspecto totalmente renovado. Recorr\xed los alrededores tomando fotos y visit\xe9 la tienda oficial, que funciona como un peque\xf1o centro comercial de acceso gratuito. Al averiguar sobre el tour interior, descubr\xed que debido a obras de mantenimiento solo estaba habilitada una peque\xf1a parte del recinto, pero el precio se manten\xeda en 35 EUR. Consider\xe9 que era costoso para una visita parcial, as\xed que desist\xed y opt\xe9 por caminar los alrededores, explorando la zona desde Nueva Espa\xf1a hasta Cuatro Caminos."}),"\n",(0,r.jsx)(e.p,{children:"A las 4:30 p.m., tom\xe9 el metro en Cuatro Caminos hacia la estaci\xf3n Estadio Metropolitano. Arrib\xe9 a las 5:10 p.m. a un lugar bastante solitario, fr\xedo y nublado. Aunque el estadio del Atl\xe9tico de Madrid estaba cerrado, disfrut\xe9 de unos 40 minutos recorriendo sus exteriores y fotografiando las zonas accesibles. Cerca de las 5:50 p.m. emprend\xed el regreso al Airbnb; ya era hora pico y el metro comenzaba a llenarse. Sent\xeda el cansancio acumulado del viaje y quer\xeda descansar para mi vuelo a Malta. Al llegar, coincid\xed con la anfitriona, quien me aconsej\xf3 una ruta m\xe1s r\xe1pida para la ma\xf1ana siguiente: combinar tren y metro en lugar de usar solo el metro."}),"\n",(0,r.jsx)(e.h3,{id:"rumbo-al-aeropuerto",children:"Rumbo al Aeropuerto"}),"\n",(0,r.jsx)(e.p,{children:"Ten\xeda que estar en el aeropuerto a las 8:00 a.m., por lo que sal\xed del alojamiento a las 6:00 a.m. Camin\xe9 unos 500 metros hacia la estaci\xf3n de tren Villaverde Alto en total oscuridad. El trayecto me gener\xf3 cierta tensi\xf3n, ya que iba cargado con todo mi equipaje y me cruc\xe9 con grupos de personas que regresaban de fiesta. Al llegar a la estaci\xf3n, tuve problemas para entender la m\xe1quina de boletos, pero un guarda de seguridad not\xf3 mi confusi\xf3n y me ayud\xf3 a comprarlo. Tras una espera de 15 minutos, abord\xe9 el primer tren, que iba medianamente lleno."}),"\n",(0,r.jsx)(e.p,{children:"El viaje tuvo su dosis de adrenalina: deb\xeda bajar en la estaci\xf3n Sol, pero mis datos m\xf3viles eran lentos y no conoc\xeda la ruta. Intent\xe9 preguntar a otros pasajeros extranjeros sin \xe9xito, hasta que un chico africano, al escucharme, me indic\xf3 amablemente que esa era mi parada justo cuando las puertas estaban por cerrar; tuve que salir corriendo para lograr bajarme."}),"\n",(0,r.jsx)(e.h3,{id:"conexi\xf3n-y-despegue",children:"Conexi\xf3n y Despegue"}),"\n",(0,r.jsx)(e.p,{children:"En Sol, intent\xe9 hacer v\xe1lido el transbordo gratuito al metro con el boleto del tren, tal como me indic\xf3 la anfitriona. Tuve un momento inc\xf3modo al no encontrar el tiquete frente a una se\xf1ora que pens\xf3 que intentaba colarme, pero finalmente apareci\xf3 y ella me ayud\xf3 a ingresar. Tom\xe9 el metro hacia Nuevos Ministerios y all\xed hice trasbordo a la l\xednea del aeropuerto hasta la estaci\xf3n T1-T2-T3, donde pagu\xe9 el suplemento obligatorio de 3 EUR."}),"\n",(0,r.jsxs)(e.p,{children:["Como volaba con Ryanair, me dirig\xed a la Terminal 1 tras caminar por un pasillo interminable. Llegu\xe9 al mostrador de check-in alrededor de las 7:30 a.m.; la fila era corta y despach\xe9 mi equipaje sin contratiempos. Esper\xe9 poco m\xe1s de una hora hasta que, a las 8:40 a.m., las pantallas anunciaron la puerta ",(0,r.jsx)(e.code,{children:"C36"})," para el vuelo ",(0,r.jsx)(e.code,{children:"RYR5382"}),". El llamado a embarque fue a las 9:20 a.m.; con calma, esper\xe9 sentado a que la larga fila avanzara antes de ingresar. Ya a bordo, nos informaron de un retraso debido al clima, y finalmente despegamos rumbo a Malta a las 10:30 a.m., con media hora de demora respecto al itinerario original."]}),"\n",(0,r.jsx)(e.h3,{id:"vuelo-de-madrid-a-malta",children:"Vuelo de Madrid a Malta"}),"\n",(0,r.jsx)(e.p,{children:"Durante el vuelo, el cansancio se mezclaba con la emoci\xf3n y los nervios de saber que ya estaba por llegar a mi destino. Logr\xe9 dormir apenas una hora, pero me mantuve atento a la ventana; entre zonas nubladas y claros, divis\xe9 una isla alargada y muy peculiar que capt\xf3 mi curiosidad. M\xe1s tarde descubr\xed que se trataba de Formentera, ubicada al sur de Ibiza."}),"\n",(0,r.jsx)(e.h3,{id:"llegada-a-malta",children:"Llegada a Malta"}),"\n",(0,r.jsx)(e.p,{children:"Aterric\xe9 en el Aeropuerto Internacional de Malta el domingo 26 de enero de 2025, alrededor de las 12:35 p.m. Un autob\xfas nos traslad\xf3 desde el avi\xf3n hasta la terminal y, tras cruzar un largo pasillo, llegu\xe9 a la zona de arribos. All\xed me conect\xe9 al internet del aeropuerto para contactar al conductor de la agencia, un colombiano con quien hab\xeda coordinado previamente por WhatsApp. \xc9l nos recogi\xf3 a m\xed y a otra chica colombiana que viajaba en el mismo vuelo."}),"\n",(0,r.jsx)(e.p,{children:"Como mi alojamiento estaba m\xe1s cerca, fui el primero en ser llevado. Durante el trayecto, tuve mi primer contacto con la arquitectura maltesa; sus edificios antiguos y el estilo colonial de las casas me dejaron una excelente primera impresi\xf3n. Al llegar frente a la casa, el conductor me entreg\xf3 una mochila con un adaptador de corriente (de tipo A a tipo G brit\xe1nico) y una tarjeta SIM, aunque no pude instalarla en ese momento por no tener la herramienta de extracci\xf3n a la mano."}),"\n",(0,r.jsx)(e.p,{children:"Con ayuda del conductor ingres\xe9 por la puerta principal del edificio; luego \xe9l se despidi\xf3 y se march\xf3. Sub\xed hasta el tercer piso \u2014que para un colombiano equivaldr\xeda al cuarto, ya que en Malta los edificios comienzan a contar desde la planta baja o piso cero\u2014. Las instrucciones del anfitri\xf3n para entrar al apartamento no eran claras, por lo que tard\xe9 unos diez minutos en descifrarlas. Al ingresar, me qued\xe9 esperando en la sala, ya que no sab\xeda cu\xe1l era mi lugar asignado. El lugar funcionaba como un alojamiento compartido tipo hostel: un apartamento amplio con tres habitaciones equipadas con camarotes, dos ba\xf1os, cocina y sala, con capacidad para 14 personas (6 hombres y 8 mujeres)."}),"\n",(0,r.jsx)(e.h3,{id:"instalaci\xf3n-y-reconocimiento-de-la-zona",children:"Instalaci\xf3n y reconocimiento de la zona"}),"\n",(0,r.jsx)(e.p,{children:'Unos 40 minutos despu\xe9s lleg\xf3 uno de los encargados. Al saludarlo con mi ingl\xe9s b\xe1sico, not\xf3 mi acento y rasgos latinos e inmediatamente me pregunt\xf3: "\xbfEres colombiano?". Result\xf3 ser un compatriota que llevaba tres meses en la isla estudiando y realizando un voluntariado en el alojamiento. Fue muy amable, me asign\xf3 mi cama y me explic\xf3 las normas de la casa. Guard\xe9 mi computador en el locker de seguridad.'}),"\n",(0,r.jsx)(e.p,{children:"Cerca de las 2:45 p.m., sal\xed a explorar el vecindario. Camin\xe9 cinco cuadras hasta la playa para disfrutar de las vistas y luego ubiqu\xe9 el Lidl, el supermercado m\xe1s popular de la isla por sus buenos precios bajos, similar al D1 en colombia, que afortunadamente quedaba cerca. Compr\xe9 la cena y el desayuno para el d\xeda siguiente y regres\xe9 al Airbnb. En el apartamento conoc\xed e hice unos amigos: una colombiana, un argentino, un chico de T\xfanez y un ruso-alem\xe1n un poco raro pero muy buena onda. Agotado por el viaje, dej\xe9 todo listo y me fui a descansar."}),"\n",(0,r.jsx)(e.h3,{id:"primer-d\xeda-de-clases",children:"Primer d\xeda de clases"}),"\n",(0,r.jsx)(e.p,{children:"El lunes 27 de enero me levant\xe9 temprano, lleno de expectativas por mi primer d\xeda. Prepar\xe9 el desayuno y camin\xe9 hacia la escuela, gui\xe1ndome con Google Maps; hab\xeda elegido el alojamiento estrat\xe9gicamente por su cercan\xeda. Deb\xeda estar all\xed a las 8:00 a.m."}),"\n",(0,r.jsxs)(e.p,{children:["El grupo de nuevos estudiantes estaba conformado por unas ocho personas de varias nacionalidades: Alemania, Polonia, Corea y yo, el \xfanico colombiano. Fuimos divididos por niveles y yo qued\xe9 asignado al grupo A2 (Pre-intermedio). Nos reunieron en un sal\xf3n donde la directora de ",(0,r.jsx)(e.code,{children:"AM Language"}),", de origen indio, nos dio la bienvenida totalmente en ingl\xe9s. All\xed nos explicaron el proceso acad\xe9mico y me entregaron el material de estudio: el libro Outcomes de National Geographic."]}),"\n",(0,r.jsx)(e.h3,{id:"el-inicio-de-las-clases",children:"El inicio de las clases"}),"\n",(0,r.jsx)(e.p,{children:"Tras la reuni\xf3n de bienvenida, a las 9:00 a.m., lleg\xf3 el momento de mi primera clase. Me dirig\xed con una mezcla de nervios, ansiedad y emoci\xf3n al sal\xf3n n\xfamero 5, ubicado en el primer piso. Casi todos los estudiantes ya estaban all\xed y la sesi\xf3n comenz\xf3 cinco minutos despu\xe9s. Aunque me present\xe9 con timidez debido a mi nivel b\xe1sico, logr\xe9 hacerlo con fluidez. \xc9ramos un grupo diverso de seis personas: Otto, un joven alem\xe1n de unos 20 a\xf1os que tambi\xe9n era nuevo en el curso ese d\xeda; Marina, de Brasil; Iza, de Per\xfa; Brigitte, de Alemania; Enzo, de Italia; y yo."}),"\n",(0,r.jsx)(e.p,{children:"La profesora, Martine, era de origen franc\xe9s, pero tras vivir mucho tiempo en pa\xedses angloparlantes, ten\xeda un gran dominio del idioma, casi nativo. Su energ\xeda contagiosa hizo que la clase fuera muy interesante y divertida; adem\xe1s, su pronunciaci\xf3n era muy clara que logr\xe9 entender la mayor parte de lo que dec\xeda."}),"\n",(0,r.jsx)(e.p,{children:"Como es costumbre los lunes, iniciamos un nuevo tema: el cap\xedtulo 9 del libro, titulado \u201cYour place\u201d. Durante la jornada, aprend\xed y practiqu\xe9 vocabulario sobre el clima, el entorno urbano y el tr\xe1fico, adem\xe1s de frases comunes en ingl\xe9s. En total fueron tres horas de aprendizaje, divididas en un primer bloque de 9:00 a 10:30 a.m., seguido de un descanso de media hora, para retomar de 11:00 a.m. a 12:30 p.m."}),"\n",(0,r.jsx)(e.hr,{}),"\n",(0,r.jsxs)(e.p,{children:[(0,r.jsx)(e.strong,{children:"Nota del autor"}),": Esta historia y las experiencias vividas son reales y de mi autor\xeda. Sin embargo, utilic\xe9 herramientas de Inteligencia Artificial para pulir la redacci\xf3n, mejorar la gram\xe1tica y asegurar que la lectura fuera m\xe1s fluida."]})]})}function u(a={}){const{wrapper:e}={...(0,i.R)(),...a.components};return e?(0,r.jsx)(e,{...a,children:(0,r.jsx)(c,{...a})}):c(a)}},8453:(a,e,o)=>{o.d(e,{R:()=>l,x:()=>s});var n=o(6540);const r={},i=n.createContext(r);function l(a){const e=n.useContext(i);return n.useMemo(function(){return"function"==typeof a?a(e):{...e,...a}},[e,a])}function s(a){let e;return e=a.disableParentContext?"function"==typeof a.components?a.components(r):a.components||r:l(a.components),n.createElement(i.Provider,{value:e},a.children)}}}]);